"use strict";(self.webpackChunkfinephrase_vi=self.webpackChunkfinephrase_vi||[]).push([["7849"],{171(n){n.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","href":"/finephrase-vi/docs/gioi_thieu","label":"1. Gi\u1EDBi thi\u1EC7u","docId":"gioi_thieu","unlisted":false},{"type":"link","href":"/finephrase-vi/docs/thiet_lap","label":"2. Thi\u1EBFt l\u1EADp","docId":"thiet_lap","unlisted":false},{"type":"link","href":"/finephrase-vi/docs/thi_nghiem","label":"3. Th\xed nghi\u1EC7m","docId":"thi_nghiem","unlisted":false},{"type":"link","href":"/finephrase-vi/docs/phan_tich","label":"4. Ph\xe2n t\xedch","docId":"phan_tich","unlisted":false},{"type":"link","href":"/finephrase-vi/docs/ha_tang","label":"5. H\u1EA1 t\u1EA7ng","docId":"ha_tang","unlisted":false},{"type":"link","href":"/finephrase-vi/docs/finephrase","label":"6. FinePhrase","docId":"finephrase","unlisted":false},{"type":"link","href":"/finephrase-vi/docs/ket_luan","label":"7. K\u1EBFt lu\u1EADn","docId":"ket_luan","unlisted":false},{"type":"link","href":"/finephrase-vi/docs/phu_luc","label":"8. Ph\u1EE5 l\u1EE5c","docId":"phu_luc","unlisted":false}]},"docs":{"finephrase":{"id":"finephrase","title":"\u{1F6E0}\uFE0F X\xe2y d\u1EF1ng FinePhrase","description":"Khi c\xe1c th\xed nghi\u1EC7m \u0111\xe3 ho\xe0n t\u1EA5t v\xe0 h\u1EA1 t\u1EA7ng \u0111\xe3 \u0111\u01B0\u1EE3c th\u1EED nghi\u1EC7m th\u1EF1c t\u1EBF qua c\xe1c \u0111\u1EE3t ch\u1EA1y th\u1EED, \u0111\xe3 \u0111\u1EBFn l\xfac ch\xfang t\xf4i t\u1ED5ng h\u1EE3p m\u1ECDi th\u1EE9 l\u1EA1i v\u1EDBi nhau. Ch\xfang t\xf4i \xe1p d\u1EE5ng c\xe1c ph\xe1t hi\u1EC7n c\u1EE7a m\xecnh \u0111\u1EC3 x\xe2y d\u1EF1ng FinePhrase, m\u1ED9t t\u1EADp d\u1EEF li\u1EC7u t\u1ED5ng h\u1EE3p quy m\xf4 l\u1EDBn di\u1EC5n \u0111\u1EA1t l\u1EA1i 339 tri\u1EC7u t\xe0i li\u1EC7u t\u1EEB FineWeb-Edu (ph\u1EA7n sample-350BT) th\xe0nh b\u1ED1n \u0111\u1ECBnh d\u1EA1ng c\u1EA5u tr\xfac kh\xe1c nhau, t\u1EA1o ra 1,35 t\u1EF7 m\u1EABu v\xe0 486 t\u1EF7 token \u0111\u1EA7u ra (completion tokens) cho d\u1EEF li\u1EC7u ti\u1EC1n hu\u1EA5n luy\u1EC7n (pretraining) t\u1ED5ng h\u1EE3p.","sidebar":"tutorialSidebar"},"gioi_thieu":{"id":"gioi_thieu","title":"\u{1F4DD} Playbook D\u1EEF li\u1EC7u T\u1ED5ng h\u1EE3p: T\u1EA1o ra h\xe0ng ngh\xecn t\u1EF7 Token ch\u1EA5t l\u01B0\u1EE3ng nh\u1EA5t","description":"T\xe1c gi\u1EA3: Hugging Face","sidebar":"tutorialSidebar"},"ha_tang":{"id":"ha_tang","title":"\u{1F3D7}\uFE0F H\u1EA1 t\u1EA7ng","description":"M\u1ED7i c\u1EA5u h\xecnh rephrasing (di\u1EC5n \u0111\u1EA1t l\u1EA1i) trong s\u1ED1 90 c\u1EA5u h\xecnh c\u1EE7a ch\xfang t\xf4i y\xeau c\u1EA7u sinh kho\u1EA3ng 10 t\u1EF7 token v\u0103n b\u1EA3n web. Ngay c\u1EA3 khi s\u1EED d\u1EE5ng KV caching (b\u1ED9 nh\u1EDB \u0111\u1EC7m KV), m\u1ED7i token \u0111\u1EA7u ra v\u1EABn c\u1EA7n m\u1ED9t l\u01B0\u1EE3t truy\u1EC1n xu\xf4i (forward pass) ri\xeang, v\xe0 m\u1ED7i t\xe0i li\u1EC7u web ch\u1EE9a t\u1EDBi v\xe0i ngh\xecn token. N\u1EBFu c\u1EA5u h\xecnh ph\u1EE5c v\u1EE5 (serving config) kh\xf4ng t\u1ED1i \u01B0u, m\u1ED9t l\u01B0\u1EE3t ch\u1EA1y sinh d\u1EEF li\u1EC7u c\xf3 th\u1EC3 m\u1EA5t v\xe0i tu\u1EA7n thay v\xec v\xe0i ng\xe0y. Nh\xe2n con s\u1ED1 \u0111\xf3 v\u1EDBi 90, s\u1EF1 kh\xe1c bi\u1EC7t gi\u1EEFa m\u1ED9t thi\u1EBFt l\u1EADp t\u1ED1t v\xe0 m\u1ED9t thi\u1EBFt l\u1EADp t\u1ED3i t\u1EC7 th\u1EF1c s\u1EF1 t\u01B0\u01A1ng \u0111\u01B0\u01A1ng v\u1EDBi h\xe0ng th\xe1ng tr\u1EDDi ch\u1EA1y GPU.","sidebar":"tutorialSidebar"},"ket_luan":{"id":"ket_luan","title":"\u{1F3C1} K\u1EBFt lu\u1EADn","description":"Ch\xfang t\xf4i \u0111\xe3 th\u1EF1c hi\u1EC7n 333 th\xed nghi\u1EC7m hu\u1EA5n luy\u1EC7n-v\xe0-\u0111\xe1nh gi\xe1 tr\xean 90 c\u1EA5u h\xecnh rephrasing (di\u1EC5n \u0111\u1EA1t l\u1EA1i) \u0111\u1EC3 l\xe0m s\xe1ng t\u1ECF nh\u1EEFng y\u1EBFu t\u1ED1 th\u1EF1c s\u1EF1 quan tr\u1ECDng \u0111\u1ED1i v\u1EDBi d\u1EEF li\u1EC7u ti\u1EC1n hu\u1EA5n luy\u1EC7n (pretraining) t\u1ED5ng h\u1EE3p. Ri\xeang vi\u1EC7c t\u1EA1o ra c\xe1c t\u1EADp d\u1EEF li\u1EC7u t\u1ED5ng h\u1EE3p n\xe0y \u0111\xe3 ti\xeau t\u1ED1n h\u01A1n 1 ngh\xecn t\u1EF7 token v\xe0 h\u01A1n 111.000 gi\u1EDD GPU. C\xe2u tr\u1EA3 l\u1EDDi thu \u0111\u01B0\u1EE3c \u0111\u01A1n gi\u1EA3n \u0111\u1EBFn ng\u1EA1c nhi\xean 1,35 t\u1EF7 m\u1EABu v\xe0 486 t\u1EF7 token \u0111\u1EA7u ra \u0111\u01B0\u1EE3c sinh ra t\u1EEB 339 tri\u1EC7u t\xe0i li\u1EC7u ngu\u1ED3n. B\u1EA1n kh\xf4ng c\u1EA7n m\u1ED9t m\xf4 h\xecnh di\u1EC5n \u0111\u1EA1t l\u1EA1i kh\u1ED5ng l\u1ED3 \u0111\u1EC3 \u0111\u1EA1t \u0111\u01B0\u1EE3c \u0111i\u1EC1u \u0111\xf3: m\u1ED9t m\xf4 h\xecnh k\xedch th\u01B0\u1EDBc 1B l\xe0 \u0111\u1EE7 cho h\u1EA7u h\u1EBFt c\xe1c prompt, v\xe0 ngay c\u1EA3 d\u1EEF li\u1EC7u ngu\u1ED3n ch\u1EA5t l\u01B0\u1EE3ng th\u1EA5p v\u1EABn ho\u1EA1t \u0111\u1ED9ng t\u1ED1t khi \u0111\u01B0\u1EE3c k\u1EBFt h\u1EE3p v\u1EDBi m\u1ED9t t\u1EADp d\u1EEF li\u1EC7u mix-in m\u1EA1nh m\u1EBD. T\xednh \u0111a d\u1EA1ng c\u1EE7a template quan tr\u1ECDng h\u01A1n m\u1EE9c \u0111\u1ED9 trau chu\u1ED1t c\u1EE7a template, v\xe0 m\u1ED9t m\xf4 h\xecnh sinh d\u1EEF li\u1EC7u \\"k\xe9m ho\xe0n h\u1EA3o\\" h\u01A1n nh\u01B0ng t\u1EA1o ra \u0111\u1EA7u ra \u0111a d\u1EA1ng c\xf3 th\u1EC3 v\u01B0\u1EE3t tr\u1ED9i h\u01A1n m\u1ED9t m\xf4 h\xecnh b\xf3ng b\u1EA9y nh\u01B0ng li\xean t\u1EE5c l\u1EB7p l\u1EA1i c\xf9ng m\u1ED9t c\u1EA5u tr\xfac. SmolLM2-1.7B n\u1ED5i l\xean l\xe0 m\xf4 h\xecnh di\u1EC5n \u0111\u1EA1t l\u1EA1i t\u1ED1t nh\u1EA5t tr\xean t\u1EA5t c\u1EA3 c\xe1c c\u1EA5u h\xecnh prompt, \u0111\xe1nh b\u1EA1i c\xe1c m\xf4 h\xecnh l\u1EDBn h\u01A1n t\u1EEB c\xe1c h\u1ECD m\xf4 h\xecnh kh\xe1c. Kh\xf4ng c\xf3 th\u01B0\u1EDBc \u0111o \u0111\u1EA1i di\u1EC7n (proxy metric) \u0111\xe1ng tin c\u1EADy n\xe0o c\xf3 th\u1EC3 thay th\u1EBF vi\u1EC7c hu\u1EA5n luy\u1EC7n v\xe0 \u0111\xe1nh gi\xe1 tr\u1EF1c ti\u1EBFp tr\xean m\xf4 h\xecnh th\u1EF1c t\u1EBF, v\xec v\u1EADy kh\xf4ng c\xf3 l\u1ED1i t\u1EAFt n\xe0o \u0111\u1EC3 b\u1ECF qua to\xe0n b\u1ED9 pipeline n\xe0y. Ch\xfang t\xf4i m\u1EDF ngu\u1ED3n to\xe0n b\u1ED9 h\u1EA1 t\u1EA7ng, prompt, v\xe0 m\xe3 ngu\u1ED3n benchmarking th\xf4ng qua DataTrove \u0111\u1EC3 b\u1EA1n c\xf3 th\u1EC3 k\u1EBF th\u1EEBa c\xe1c ph\xe1t hi\u1EC7n n\xe0y m\xe0 kh\xf4ng c\u1EA7n x\xe2y d\u1EF1ng l\u1EA1i h\u1EC7 th\u1ED1ng c\u1ED1t l\xf5i t\u1EEB \u0111\u1EA7u. M\u1EB7c d\xf9 v\u1EADy, v\u1EABn c\xf2n r\u1EA5t nhi\u1EC1u \u0111i\u1EC1u th\xfa v\u1ECB \u0111\u1EC3 kh\xe1m ph\xe1 \u1EDF ph\xeda tr\u01B0\u1EDBc.","sidebar":"tutorialSidebar"},"phan_tich":{"id":"phan_tich","title":"\u{1F50D} Ph\xe2n t\xedch: T\u1EA1i sao Di\u1EC5n \u0111\u1EA1t l\u1EA1i ho\u1EA1t \u0111\u1ED9ng?","description":"C\xe1c th\xed nghi\u1EC7m cho bi\u1EBFt c\u1EA5u h\xecnh n\xe0o ho\u1EA1t \u0111\u1ED9ng hi\u1EC7u qu\u1EA3. Gi\u1EDD h\xe3y c\xf9ng thu nh\u1ECF g\xf3c nh\xecn \u0111\u1EC3 l\xfd gi\u1EA3i t\u1EA1i sao. Ch\xfang t\xf4i b\u1EAFt \u0111\u1EA7u b\u1EB1ng vi\u1EC7c ki\u1EC3m ch\u1EE9ng xem \u0111i\u1EC3m s\u1ED1 benchmark t\u0103ng l\xean c\xf3 th\u1EF1c s\u1EF1 ph\u1EA3n \xe1nh n\u0103ng l\u1EF1c th\u1EF1c t\u1EBF hay ch\u1EC9 l\xe0 do r\xf2 r\u1EC9 d\u1EEF li\u1EC7u (contamination), ti\u1EBFp \u0111\xf3 l\xe0 ph\xe2n t\xedch chi ph\xed t\xe0i nguy\xean, kh\u1EA3 n\u0103ng s\u1EED d\u1EE5ng c\xe1c metric proxy gi\xe1 r\u1EBB thay th\u1EBF cho hu\u1EA5n luy\u1EC7n th\u1EF1c t\u1EBF, \u1EA3nh h\u01B0\u1EDFng c\u1EE7a quy m\xf4 m\xf4 h\xecnh h\u1ECDc sinh (student), \u0111\u1ED9 d\xe0i/c\u1EA5u tr\xfac c\u1EE7a v\u0103n b\u1EA3n di\u1EC5n \u0111\u1EA1t l\u1EA1i v\xe0 b\xe0i h\u1ECDc t\u1EEB s\u1EF1 s\u1EE5p \u0111\u1ED5 template c\u1EE7a b\xe0i to\xe1n to\xe1n h\u1ECDc.","sidebar":"tutorialSidebar"},"phu_luc":{"id":"phu_luc","title":"\u{1F4DA} Ph\u1EE5 l\u1EE5c","description":"Chi ti\u1EBFt v\u1EC1 c\xe1c th\xed nghi\u1EC7m","sidebar":"tutorialSidebar"},"thi_nghiem":{"id":"thi_nghiem","title":"\u{1F9EA} Th\xed nghi\u1EC7m: Kh\xe1m ph\xe1 Kh\xf4ng gian Di\u1EC5n \u0111\u1EA1t l\u1EA1i (Rephrasing Space)","description":"\u0110\xe3 \u0111\u1EBFn l\xfac \u0111\u01B0a t\u1EA5t c\u1EA3 c\xe1c gi\u1EA3 thuy\u1EBFt v\xe0o ki\u1EC3m ch\u1EE9ng th\u1EF1c t\u1EBF. Ch\xfang t\xf4i \u0111\xe3 t\u1EA1o ra 90 c\u1EA5u h\xecnh rephrasing, sau \u0111\xf3 th\u1EF1c hi\u1EC7n 333 th\xed nghi\u1EC7m hu\u1EA5n luy\u1EC7n-v\xe0-\u0111\xe1nh gi\xe1 \u0111\u1EC3 tr\u1EA3 l\u1EDDi m\u1ED9t c\xe1ch h\u1EC7 th\u1ED1ng cho c\xe1c c\xe2u h\u1ECFi c\u1EE7a m\xecnh. H\xe0nh tr\xecnh n\xe0y \u0111\xe3 mang l\u1EA1i m\u1ED9t s\u1ED1 b\u1EA5t ng\u1EDD th\xfa v\u1ECB ngo\xe0i d\u1EF1 ki\u1EBFn. D\u01B0\u1EDBi \u0111\xe2y l\xe0 b\u1EE9c tranh to\xe0n c\u1EA3nh v\u1EC1 kh\xf4ng gian rephrasing m\xe0 ch\xfang t\xf4i \u0111\xe3 kh\xe1m ph\xe1, t\u1EEB c\xe1c t\u1EADp d\u1EEF li\u1EC7u ngu\u1ED3n, qua c\xe1c chi\u1EBFn l\u01B0\u1EE3c prompt, cho \u0111\u1EBFn c\xe1c h\u1ECD m\xf4 h\xecnh:","sidebar":"tutorialSidebar"},"thiet_lap":{"id":"thiet_lap","title":"\u2699\uFE0F Thi\u1EBFt l\u1EADp: Di\u1EC5n \u0111\u1EA1t l\u1EA1i m\u1EA1ng Web","description":"M\u1ED9t v\xe0i \u0111\u1ED9i ng\u0169 nghi\xean c\u1EE9u \u0111\xe3 ch\u1EE9ng minh r\u1EB1ng vi\u1EC7c di\u1EC5n \u0111\u1EA1t l\u1EA1i (rephrasing) n\u1ED9i dung web th\xe0nh c\xe1c \u0111\u1ECBnh d\u1EA1ng s\u1EA1ch h\u01A1n c\xf3 th\u1EC3 mang l\u1EA1i k\u1EBFt qu\u1EA3 t\u1ED1t h\u01A1n so v\u1EDBi vi\u1EC7c hu\u1EA5n luy\u1EC7n tr\u1EF1c ti\u1EBFp tr\xean d\u1EEF li\u1EC7u th\xf4:","sidebar":"tutorialSidebar"}}}}')}}]);